script.content:
klog.info("一键导出数据处理时间开始:" + kutils.getNow("yyyy-MM-dd HH:mm:ss.SSS"));

// 获取*.pine的数据
var result = context.get('result');
result = result?.substring(5); //去掉 file|
var pineDateFilename = result?.substring(0, result?.indexOf("|"));
var pineDataJson = result?.substring(result?.indexOf("|") + 1);
var pineData = JSON.parse(pineDataJson);

// 获取参数
var appData = getResult('appData')
var datasources = appData['datasources']
var appShortName = pineData?.info['short_name']
var versionType = appData?.info['versionType']; //打包类型 linux或windows ,可能info值得到

// 定义地址
var currDir = kutils.getCurrDirectory();
var productPackagePath = `${currDir}/../package2/` // 半成品
var uploadPackagePath = `${currDir}/upload/package2/` // 成品、上传/下载目录
var productPath = 'product/'
var systemProductPath = versionType == 'linux' ? 'linux/' : 'windows/'
// klog.info('--------------type: ' + versionType + '---------' + JSON.stringify(appData))
// 生成本次成品唯一文件名
var fileName = appShortName + '_' + getUuid()
var fullFileName = uploadPackagePath + fileName

// 复制半成品，开始组装成品
kutils.fileCopy(productPackagePath + productPath, fullFileName); //复制
kutils.fileCopy(productPackagePath + systemProductPath, fullFileName); //复制

// 动态替换变量
function initReplace(txt, obj){
	for(var k in obj){		
		var key = line2Hump(k);
		// klog.info('==fileRead==|' + k + '|' + key + '|' + obj[k]);
		txt = txt.replaceAll('${' + key + '}', obj[k]);
	}
	return txt;
}

// 动态替换配置
var dynamicConfigList = [{
 id: 'applicationProperties',
 file: '/api/application.properties'
}, {
 id: 'db',
 file: '/api/db.json'
}, {
 id: 'faasConfig',
 file: '/faas/config.json'
}]
dynamicConfigList?.forEach(item => {
 var fileFullPath = fullFileName + item?.file
 if (item?.id === 'db' && datasources) {
 datasources = datasources?.map(dbSource => {
 return {
 ...dbSource,
 userName: dbSource.username
 }
 })
 kutils.fileUpload(JSON.stringify(datasources), fileFullPath, "GBK")
 } else {
 var fileTxt = kutils.fileRead(fileFullPath) //读出
 fileTxt = initReplace(fileTxt, pineData['info']) //替换
 kutils.fileUpload(fileTxt, fileFullPath, 'GBK')//写入
 }
})

var pineFilePath = fullFileName + `/api/${fileName}.pine`
kutils.fileUpload(pineDataJson, pineFilePath, "GBK")

//压缩k-pine.version.time目录为k-pine.version.time.zip,并读取zip包内容返回到前端
var downloadFileName = `package2/${fileName}.zip`
klog.info("开始压缩时间:" + kutils.getNow('yyyy-MM-dd HH:mm:ss.SSS'));
kutils.zip(fullFileName, fullFileName + '.zip', '');
klog.info('完成压缩时间:' + kutils.getNow('yyyy-MM-dd HH:mm:ss.SSS'));

//txt = kutils.fileRead(setupPath + pine_new + '.zip'); 
//setResult('result', 'file|' + pine_new + '.zip' + '|' + txt);
setResult('result', downloadFileName);

var applicationConfig = context.get('applicationConfig');
var exportData = context.get('exportData');
var export_data = {};
export_data["exportData"] = JSON.parse(exportData);
export_data["applicationConfig"] = JSON.parse(applicationConfig);

var data = {};
data["app_id"] = pineData['info']['id']
data["version"] = pineData['info']['version']
data["file_name"] = downloadFileName
data["export_data"] = JSON.stringify(export_data)
setResult('data', data);

//删除setupPath + pine_new目录
kutils.fileDelete(fullFileName); //删除

klog.info("一键导出数据处理时间结束:" + kutils.getNow("yyyy-MM-dd HH:mm:ss.SSS"));
